#!/usr/bin/env node
import fs from 'node:fs';
import path from 'node:path';
import http from 'node:http';
import crypto from 'node:crypto';
import { createRequire } from 'node:module';
import initSqlJs from 'sql.js';
import YAML from 'yaml';

const require = createRequire(import.meta.url);
let SQL;
const redFlags = ['unpaid', 'commission only', 'commission-only', 'no salary', 'equity only', '1099 only', 'must pay', 'training fee'];
const validStatuses = new Set(['saved', 'researching', 'materials-ready', 'applied', 'recruiter-screen', 'interview', 'offer', 'rejected', 'withdrawn', 'ghosted']);

function hash(s) { return crypto.createHash('sha256').update(String(s)).digest('hex').slice(0, 12); }
function id(prefix, seed) { return `${prefix}_${hash(seed)}`; }
function slug(s) { return String(s || '').trim().toLowerCase().replace(/['"]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '') || 'untitled'; }
function now() { return new Date().toISOString(); }
function root(flags = {}) { return path.resolve(flags.workspace || process.env.JOBOS_HOME || process.cwd()); }
function paths(r) { return { root:r, state:path.join(r,'.jobos'), db:path.join(r,'.jobos','jobos.sqlite'), ws:path.join(r,'jobos-workspace'), profiles:path.join(r,'jobos-workspace','profiles'), proofs:path.join(r,'jobos-workspace','proof-points'), jobs:path.join(r,'jobos-workspace','jobs'), exports:path.join(r,'jobos-workspace','exports'), automations:path.join(r,'jobos-workspace','automations') }; }
function mkdirs(p) { for (const d of [p.state,p.ws,p.profiles,p.proofs,p.jobs,p.exports,p.automations]) fs.mkdirSync(d,{recursive:true}); }
function writeYaml(file, value) { fs.mkdirSync(path.dirname(file),{recursive:true}); fs.writeFileSync(file, YAML.stringify(value,{lineWidth:0})); }
function writeMd(file, value) { fs.mkdirSync(path.dirname(file),{recursive:true}); fs.writeFileSync(file, value.endsWith('\n') ? value : value+'\n'); }
function j(s, fb) { try { return s ? JSON.parse(s) : fb; } catch { return fb; } }
function tokenize(s) { return String(s||'').toLowerCase().replace(/[^a-z0-9+#.]+/g,' ').split(/\s+/).filter(t => t.length>2 && !['the','and','with','for','you','our','are','will','this','that','from'].includes(t)); }
function esc(s) { return String(s??'').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }

const schema = `PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS meta (key TEXT PRIMARY KEY, value TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS profiles (id TEXT PRIMARY KEY, name TEXT NOT NULL, preferences_json TEXT NOT NULL, resume_text TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS proof_points (id TEXT PRIMARY KEY, profile_id TEXT NOT NULL, summary TEXT NOT NULL, evidence TEXT NOT NULL DEFAULT '', skills_json TEXT NOT NULL DEFAULT '[]', source TEXT NOT NULL DEFAULT 'manual', created_at TEXT NOT NULL, FOREIGN KEY(profile_id) REFERENCES profiles(id));
CREATE TABLE IF NOT EXISTS companies (id TEXT PRIMARY KEY, name TEXT NOT NULL, website TEXT NOT NULL DEFAULT '', summary TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS jobs (id TEXT PRIMARY KEY, profile_id TEXT NOT NULL, company_id TEXT, title TEXT NOT NULL, company TEXT NOT NULL, location TEXT NOT NULL DEFAULT '', url TEXT NOT NULL DEFAULT '', source TEXT NOT NULL DEFAULT 'manual', description TEXT NOT NULL, requirements_json TEXT NOT NULL DEFAULT '[]', compensation TEXT NOT NULL DEFAULT '', work_model TEXT NOT NULL DEFAULT '', status TEXT NOT NULL DEFAULT 'imported', fit_score INTEGER, score_json TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(profile_id,url), FOREIGN KEY(profile_id) REFERENCES profiles(id));
CREATE TABLE IF NOT EXISTS stakeholders (id TEXT PRIMARY KEY, job_id TEXT, company_id TEXT, name TEXT NOT NULL, role TEXT NOT NULL DEFAULT '', links_json TEXT NOT NULL DEFAULT '[]', summary TEXT NOT NULL DEFAULT '', outreach_status TEXT NOT NULL DEFAULT 'not_contacted', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS applications (id TEXT PRIMARY KEY, job_id TEXT NOT NULL, profile_id TEXT NOT NULL, status TEXT NOT NULL, notes TEXT NOT NULL DEFAULT '', confirmation_url TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, UNIQUE(job_id,profile_id));
CREATE TABLE IF NOT EXISTS artifacts (id TEXT PRIMARY KEY, job_id TEXT, profile_id TEXT, type TEXT NOT NULL, path TEXT NOT NULL, title TEXT NOT NULL, content TEXT NOT NULL, evidence_json TEXT NOT NULL DEFAULT '[]', warnings_json TEXT NOT NULL DEFAULT '[]', approval_status TEXT NOT NULL DEFAULT 'draft_needs_human_review', created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS tasks (id TEXT PRIMARY KEY, job_id TEXT, application_id TEXT, title TEXT NOT NULL, description TEXT NOT NULL DEFAULT '', type TEXT NOT NULL DEFAULT 'review', due_at TEXT, priority TEXT NOT NULL DEFAULT 'normal', status TEXT NOT NULL DEFAULT 'open', created_by TEXT NOT NULL DEFAULT 'system', created_at TEXT NOT NULL, updated_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS automation_runs (id TEXT PRIMARY KEY, trigger_name TEXT NOT NULL, inputs_json TEXT NOT NULL DEFAULT '{}', outputs_json TEXT NOT NULL DEFAULT '{}', status TEXT NOT NULL, external_side_effects TEXT NOT NULL DEFAULT 'none', created_at TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS audit_log (id TEXT PRIMARY KEY, action TEXT NOT NULL, entity_type TEXT NOT NULL, entity_id TEXT NOT NULL, payload_json TEXT NOT NULL DEFAULT '{}', external_side_effect TEXT NOT NULL DEFAULT 'none', created_at TEXT NOT NULL);`;

async function open(flags={}) {
  const r = root(flags), p = paths(r); mkdirs(p);
  if (!SQL) SQL = await initSqlJs({ locateFile: f => path.join(path.dirname(require.resolve('sql.js')), f) });
  const db = fs.existsSync(p.db) ? new SQL.Database(fs.readFileSync(p.db)) : new SQL.Database();
  db.run(schema); db.run('INSERT OR REPLACE INTO meta VALUES (?,?)',['schema_version','1']);
  const scheduler = path.join(p.automations,'scheduler-design.json');
  if (!fs.existsSync(scheduler)) fs.writeFileSync(scheduler, JSON.stringify({version:1,note:'Future cron/queue shape. MVP automation is manual via jobos review weekly.',jobs:[{id:'weekly-review',command:'jobos review weekly --profile <profile> --output markdown',schedule:'0 9 * * 5',externalSideEffects:false},{id:'daily-discovery',command:'jobos jobs import-url <url> --profile <profile>',schedule:'0 7 * * 1-5',status:'design-only'}],policy:{autoApply:'disabled',autoSend:'disabled',defaultExternalActions:'human_approval_required'}},null,2)+'\n');
  const store = {db, p, root:r}; save(store); return store;
}
function save(s) { fs.writeFileSync(s.p.db, Buffer.from(s.db.export())); }
function all(s, sql, params=[]) { const st=s.db.prepare(sql,params), rows=[]; try { while(st.step()) rows.push(st.getAsObject()); } finally { st.free(); } return rows; }
function one(s, sql, params=[]) { return all(s,sql,params)[0] || null; }
function run(s, sql, params=[]) { s.db.run(sql,params); }
function audit(s, action, type, eid, payload={}, side='none') { const at=now(), aid=id('audit',`${action}:${type}:${eid}:${at}:${JSON.stringify(payload)}`); run(s,'INSERT INTO audit_log VALUES (?,?,?,?,?,?,?)',[aid,action,type,eid,JSON.stringify(payload),side,at]); const evt={id:aid,action,entityType:type,entityId:eid,payload,externalSideEffect:side,createdAt:at}; fs.appendFileSync(path.join(s.p.ws,'audit.log.jsonl'),JSON.stringify(evt)+'\n'); const jid=payload.jobId || (type==='job'?eid:null); if(jid){const d=path.join(s.p.jobs,jid); fs.mkdirSync(d,{recursive:true}); fs.appendFileSync(path.join(d,'audit.log.jsonl'),JSON.stringify(evt)+'\n');} }

function defaultPrefs(name) { const ts=slug(name).split('-').filter(Boolean); return {targetRoleFamilies:[name],industries:[],locations:[],skills:ts,missionKeywords:[],workModel:'',automationPolicy:{externalApply:'human_approval_required',externalSend:'human_approval_required'}}; }
function resumeProofs(profileId, text, source) { return String(text||'').split(/\r?\n/).map(l=>l.trim().replace(/^[-*•]\s*/, '')).filter(l=>l.length>=35 && /\b(built|led|managed|created|designed|improved|launched|reduced|increased|owned|shipped|analyzed|implemented)\b/i.test(l)).slice(0,12).map(line=>({id:id('proof',`${profileId}:${line}`),summary:line,evidence:source,skills:[...new Set(tokenize(line).filter(t=>t.length>3).slice(0,8))]})); }
function syncProfile(s, pid) { const p=one(s,'SELECT * FROM profiles WHERE id=?',[pid]); if(!p) return; const proofs=all(s,'SELECT * FROM proof_points WHERE profile_id=? ORDER BY created_at',[pid]); writeYaml(path.join(s.p.profiles,`${pid}.yaml`),{id:p.id,name:p.name,preferences:j(p.preferences_json,{}),proofPoints:proofs.map(x=>({id:x.id,summary:x.summary,evidence:x.evidence,skills:j(x.skills_json,[])})),updatedAt:p.updated_at}); writeMd(path.join(s.p.proofs,`${pid}.md`), ['# Proof points for '+p.name,'',...proofs.map(x=>`- **${x.id}:** ${x.summary}${x.evidence ? ` _(evidence: ${x.evidence})_` : ''}`),''].join('\n')); }
function createProfile(s,name,opts={}) { const pid=slug(name); const ex=one(s,'SELECT * FROM profiles WHERE id=?',[pid]); if(ex) return {profile:ex,created:false}; const at=now(), resume=opts.fromResume ? fs.readFileSync(opts.fromResume,'utf8') : '', prefs=opts.preferences ? JSON.parse(fs.readFileSync(opts.preferences,'utf8')) : defaultPrefs(name); run(s,'INSERT INTO profiles VALUES (?,?,?,?,?,?)',[pid,name,JSON.stringify(prefs),resume,at,at]); const proofs=resumeProofs(pid,resume,opts.fromResume||'profile import'); for(const pr of proofs) run(s,'INSERT OR IGNORE INTO proof_points VALUES (?,?,?,?,?,?,?)',[pr.id,pid,pr.summary,pr.evidence,JSON.stringify(pr.skills),'resume_import',at]); audit(s,'profile.created','profile',pid,{proofPointsImported:proofs.length}); syncProfile(s,pid); save(s); return {profile:one(s,'SELECT * FROM profiles WHERE id=?',[pid]),created:true}; }
function addProof(s,pid,summary,evidence='',skills=[]) { if(!one(s,'SELECT id FROM profiles WHERE id=?',[pid])) throw Error(`Unknown profile: ${pid}`); const at=now(), proofId=id('proof',`${pid}:${summary}:${evidence}`); run(s,'INSERT OR IGNORE INTO proof_points VALUES (?,?,?,?,?,?,?)',[proofId,pid,summary,evidence,JSON.stringify(skills),'manual',at]); audit(s,'proof_point.added','proof_point',proofId,{profileId:pid}); syncProfile(s,pid); save(s); return one(s,'SELECT * FROM proof_points WHERE id=?',[proofId]); }
function reqs(text) { return String(text||'').split(/\r?\n/).map(l=>l.trim()).filter(Boolean).filter(l=>/require|qualification|experience|skill|must|responsibil|you will|we need|looking for/i.test(l)).slice(0,12); }
function parseJob(text, fb={}) { const lines=String(text||'').split(/\r?\n/).map(l=>l.trim()).filter(Boolean); const find=k=>lines.find(l=>new RegExp('^'+k+'\\s*:','i').test(l))?.replace(new RegExp('^'+k+'\\s*:\\s*','i'),''); const heading=lines.find(l=>/^#\s+/.test(l)); return {title:fb.title||find('title')||(heading?heading.replace(/^#\s+/,''):'Imported role'),company:fb.company||find('company')||'Unknown company',location:fb.location||find('location')||'',description:text}; }
function ensureCompany(s,name) { const cid=slug(name||'unknown-company'), at=now(); run(s,'INSERT OR IGNORE INTO companies (id,name,created_at,updated_at) VALUES (?,?,?,?)',[cid,name||'Unknown company',at,at]); return one(s,'SELECT * FROM companies WHERE id=?',[cid]); }
function syncJob(s,jid) { const job=one(s,'SELECT * FROM jobs WHERE id=?',[jid]); if(!job) return; const score=j(job.score_json,null), app=one(s,'SELECT * FROM applications WHERE job_id=?',[jid]), tasks=all(s,'SELECT * FROM tasks WHERE job_id=? ORDER BY due_at IS NULL,due_at,created_at',[jid]); const dir=path.join(s.p.jobs,jid); writeYaml(path.join(dir,'job.yaml'),{id:job.id,profileId:job.profile_id,title:job.title,company:job.company,location:job.location,url:job.url,source:job.source,requirements:j(job.requirements_json,[]),compensation:job.compensation,workModel:job.work_model,status:job.status,fitScore:job.fit_score,score,application:app?{id:app.id,status:app.status,notes:app.notes,confirmationUrl:app.confirmation_url,updatedAt:app.updated_at}:null,updatedAt:job.updated_at}); writeMd(path.join(dir,'description.md'),job.description); if(app) writeYaml(path.join(dir,'application.yaml'),{id:app.id,status:app.status,notes:app.notes,confirmationUrl:app.confirmation_url,updatedAt:app.updated_at}); if(tasks.length) writeYaml(path.join(dir,'tasks.yaml'),tasks.map(t=>({id:t.id,title:t.title,type:t.type,dueAt:t.due_at,priority:t.priority,status:t.status,createdBy:t.created_by}))); if(score) writeMd(path.join(dir,'score.md'),scoreMd(job,score)); }
function importText(s,{profileId,filePath,source='text_file',url=''}) { if(!one(s,'SELECT id FROM profiles WHERE id=?',[profileId])) throw Error(`Unknown profile: ${profileId}`); const text=fs.readFileSync(filePath,'utf8'), parsed=parseJob(text), company=ensureCompany(s,parsed.company), at=now(), jid=id('job',url||`${profileId}:${parsed.title}:${parsed.company}:${text}`); const ex=one(s,'SELECT * FROM jobs WHERE id=? OR (profile_id=? AND url != "" AND url=?)',[jid,profileId,url]); if(ex) return {job:ex,created:false}; run(s,'INSERT INTO jobs (id,profile_id,company_id,title,company,location,url,source,description,requirements_json,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)',[jid,profileId,company.id,parsed.title,parsed.company,parsed.location,url,source,text,JSON.stringify(reqs(text)),at,at]); audit(s,'job.imported','job',jid,{jobId:jid,profileId,source,url}); syncJob(s,jid); save(s); return {job:one(s,'SELECT * FROM jobs WHERE id=?',[jid]),created:true}; }
async function importUrl(s,{profileId,url}) { let text; try { const r=await fetch(url,{headers:{'user-agent':'JobOS local CLI (+human-initiated import)'}}); const html=await r.text(); const title=(html.match(/<title[^>]*>([^<]+)<\/title>/i)?.[1]||'Imported URL role').replace(/\s+/g,' ').trim(); const body=html.replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/\s+/g,' ').trim(); text=`Title: ${title}\nCompany: Unknown company\nSource URL: ${url}\n\n${body.slice(0,12000)}`; } catch(e) { text=`Title: Imported URL role\nCompany: Unknown company\nSource URL: ${url}\n\nURL import was recorded, but content fetch failed: ${e.message}\nManual enrichment required before scoring or tailoring.`; } const tmp=path.join(s.p.state,`${id('urlimport',url)}.txt`); fs.writeFileSync(tmp,text); return importText(s,{profileId,filePath:tmp,source:'url',url}); }
function listJobs(s) { return all(s,'SELECT jobs.*, applications.status AS application_status FROM jobs LEFT JOIN applications ON applications.job_id=jobs.id ORDER BY jobs.created_at DESC'); }
function overlap(jobTokens,wanted,base=50){ const w=[...new Set(wanted.filter(Boolean))]; if(!w.length) return {score:base,hits:[],reason:'No explicit preferences set; neutral score.'}; const set=new Set(jobTokens), hits=w.filter(t=>set.has(t)); return {score:Math.min(100,Math.round(base+(hits.length/w.length)*60)),hits,reason:hits.length?`Matched ${hits.join(', ')}.`:'No direct keyword match found.'}; }
function score(s,jid,pid){ const job=one(s,'SELECT * FROM jobs WHERE id=?',[jid]); if(!job) throw Error(`Unknown job: ${jid}`); const prof=one(s,'SELECT * FROM profiles WHERE id=?',[pid]); if(!prof) throw Error(`Unknown profile: ${pid}`); const prefs=j(prof.preferences_json,{}), text=`${job.title}\n${job.company}\n${job.location}\n${job.description}`, toks=tokenize(text); const role=overlap(toks,tokenize([prof.name,...(prefs.targetRoleFamilies||[]),...(prefs.skills||[])].join(' ')),35), domain=overlap(toks,tokenize([...(prefs.industries||[]),...(prefs.missionKeywords||[])].join(' ')),45), loc=overlap(toks,tokenize([...(prefs.locations||[]),prefs.workModel||''].join(' ')),50), mission=overlap(toks,tokenize([...(prefs.missionKeywords||[]),...(prefs.values||[])].join(' ')),45); const lower=text.toLowerCase(), pLower=`${prof.name} ${JSON.stringify(prefs)}`.toLowerCase(); const senior=['senior','staff','principal','lead','head of','director'].some(t=>lower.includes(t)), pSenior=['senior','staff','principal','lead','head of','director'].some(t=>pLower.includes(t)); let seniority={score:70,reason:'No strong seniority mismatch detected.'}; if(senior&&!pSenior) seniority={score:55,reason:'Job appears senior; profile does not explicitly target senior roles.'}; if(senior&&pSenior) seniority={score:85,reason:'Seniority language aligns with profile.'}; const comp=/\$|salary|compensation|base pay|k\b|benefits/i.test(text)?{score:75,reason:'Compensation or benefits language found.'}:{score:50,reason:'No compensation data found; verify manually.'}; const flags=redFlags.filter(t=>lower.includes(t)); const overall=Math.max(0,Math.min(100,Math.round(role.score*.28+domain.score*.18+seniority.score*.16+loc.score*.14+comp.score*.10+mission.score*.14-(flags.length*12)))); const out={jobId:jid,profileId:pid,overall,confidence:job.description.length>800?'medium':'low',dimensions:{roleFit:{score:role.score,reason:role.reason},domainFit:{score:domain.score,reason:domain.reason},seniority,locationWorkModel:{score:loc.score,reason:loc.reason},compensation:comp,missionInterest:{score:mission.score,reason:mission.reason}},redFlags:flags,reasoning:`Deterministic heuristic using profile preferences and job text. ${flags.length?`Red flags lowered score: ${flags.join(', ')}.`:'No configured red flags were found.'}`,generatedAt:now()}; run(s,'UPDATE jobs SET fit_score=?, score_json=?, updated_at=? WHERE id=?',[overall,JSON.stringify(out),now(),jid]); audit(s,'job.scored','job',jid,{jobId:jid,profileId:pid,overall}); syncJob(s,jid); save(s); return out; }
function scoreMd(job,sc){ const dims=Object.entries(sc.dimensions).map(([k,v])=>`- **${k}:** ${v.score}/100 — ${v.reason}`).join('\n'); const flags=sc.redFlags.length?sc.redFlags.map(f=>`- ${f}`).join('\n'):'- None detected by deterministic checks.'; return `# Fit score: ${job.title} at ${job.company}\n\nOverall: **${sc.overall}/100**\n\nConfidence: **${sc.confidence}**\n\n## Dimensions\n${dims}\n\n## Red flags\n${flags}\n\n## Reasoning\n${sc.reasoning}\n\n_Heuristic score only. Human review required before applying or sending materials._\n`; }
function relevant(job,proofs){ const jt=new Set(tokenize(`${job.title}\n${job.description}`)); return proofs.map(p=>{const skills=j(p.skills_json,[]), rel=tokenize(`${p.summary} ${skills.join(' ')}`).filter(t=>jt.has(t)).length; return {...p,skills,relevance:rel};}).sort((a,b)=>b.relevance-a.relevance); }
function saveArtifact(s,{job,prof,type,title,file,content,evidence,warnings}){ const rel=path.join('jobs',job.id,'artifacts',file), abs=path.join(s.p.ws,rel), at=now(), aid=id('artifact',`${type}:${job.id}:${prof.id}:${at}`); writeMd(abs,content); run(s,'INSERT INTO artifacts VALUES (?,?,?,?,?,?,?,?,?,?,?)',[aid,job.id,prof.id,type,rel,title,content,JSON.stringify(evidence),JSON.stringify(warnings),'draft_needs_human_review',at]); audit(s,'artifact.created','artifact',aid,{jobId:job.id,profileId:prof.id,type,path:rel,approvalStatus:'draft_needs_human_review'}); save(s); return {id:aid,path:rel,approvalStatus:'draft_needs_human_review',warnings}; }
function tailor(s,jid,pid,kind){ const job=one(s,'SELECT * FROM jobs WHERE id=?',[jid]); if(!job) throw Error(`Unknown job: ${jid}`); const prof=one(s,'SELECT * FROM profiles WHERE id=?',[pid]); if(!prof) throw Error(`Unknown profile: ${pid}`); const proofs=all(s,'SELECT * FROM proof_points WHERE profile_id=?',[pid]), chosen=relevant(job,proofs).filter(p=>p.relevance>0).slice(0,kind==='resume'?5:3), warnings=[]; if(!proofs.length) warnings.push('No proof points exist for this profile; draft intentionally avoids unsupported achievement claims.'); else if(!chosen.length) warnings.push('No proof points matched job language; add evidence before strengthening this artifact.'); const evidence=chosen.map(p=>({proofPointId:p.id,summary:p.summary,evidence:p.evidence,skills:p.skills})); const warningBlock=warnings.length?warnings.map(w=>`- ${w}`).join('\n'):'- None from deterministic evidence checks.'; if(kind==='resume'){ const bullets=chosen.length?chosen.map(p=>`- ${p.summary}${p.evidence?` _(evidence: ${p.evidence})_`:''}`).join('\n'):'- Add evidence-backed accomplishments before using this resume externally.'; const reqBlock=reqs(job.description).length?reqs(job.description).map(r=>`- ${r}`).join('\n'):'- No explicit requirements extracted from the job text.'; const content=`# Tailored resume draft — ${prof.name} for ${job.title}\n\n**Company:** ${job.company}\n\n**Approval status:** Draft; human review required before submission.\n\n## Target role summary\nUse this draft as a source-grounded outline. It includes only stored proof points; it does not invent metrics, employers, credentials, or claims.\n\n## Evidence-backed highlights\n${bullets}\n\n## Job requirements to address\n${reqBlock}\n\n## Evidence warnings\n${warningBlock}\n\n## Human review checklist\n- Confirm every claim is true and current.\n- Add missing proof points for important requirements before exporting a final resume.\n- Do not submit from JobOS; external applications remain human-gated.\n`; return saveArtifact(s,{job,prof,type:'tailored_resume',title:`Tailored resume for ${job.title}`,file:'resume-tailored.md',content,evidence,warnings}); }
  const proofParagraph=chosen.length?chosen.map(p=>`- ${p.summary}${p.evidence?` (evidence: ${p.evidence})`:''}`).join('\n'):'- [Add a verified proof point before sending.]'; const content=`# Cover letter draft — ${job.title} at ${job.company}\n\n**Approval status:** Draft; human review required before sending.\n\nDear hiring team,\n\nI am interested in ${job.title} at ${job.company}. The role appears aligned with my ${prof.name} search profile.\n\nEvidence I can safely claim from my proof library:\n${proofParagraph}\n\nI would tailor the final version after confirming the job requirements, company context, and any sensitive screening questions manually.\n\n## Evidence warnings\n${warningBlock}\n\n## External-action gate\nJobOS generated this draft only. It did not send email, submit forms, or contact anyone.\n`; return saveArtifact(s,{job,prof,type:'cover_letter',title:`Cover letter for ${job.title}`,file:'cover-letter.md',content,evidence,warnings}); }
function appCreate(s,jid,status,notes=''){ if(!validStatuses.has(status)) throw Error(`Invalid status: ${status}`); const job=one(s,'SELECT * FROM jobs WHERE id=?',[jid]); if(!job) throw Error(`Unknown job: ${jid}`); const at=now(), aid=id('app',`${jid}:${job.profile_id}`), ex=one(s,'SELECT * FROM applications WHERE id=?',[aid]); if(ex) run(s,'UPDATE applications SET status=?, notes=?, updated_at=? WHERE id=?',[status,notes||ex.notes,at,aid]); else run(s,'INSERT INTO applications VALUES (?,?,?,?,?,?,?,?)',[aid,jid,job.profile_id,status,notes,'',at,at]); const tid=id('task',`${aid}:review-next-action`); run(s,'INSERT OR IGNORE INTO tasks VALUES (?,?,?,?,?,?,?,?,?,?,?,?)',[tid,jid,aid,`Review next action for ${job.title}`,'Human-gated review before external application, outreach, or status-sensitive action.','review',at,'normal','open','system',at,at]); audit(s,ex?'application.status_changed':'application.created','application',aid,{jobId:jid,profileId:job.profile_id,status}); syncJob(s,jid); save(s); return one(s,'SELECT * FROM applications WHERE id=?',[aid]); }
function appUpdate(s,aid,status,notes=null){ if(!validStatuses.has(status)) throw Error(`Invalid status: ${status}`); const app=one(s,'SELECT * FROM applications WHERE id=?',[aid]); if(!app) throw Error(`Unknown application: ${aid}`); run(s,'UPDATE applications SET status=?, notes=?, updated_at=? WHERE id=?',[status,notes??app.notes,now(),aid]); audit(s,'application.status_changed','application',aid,{jobId:app.job_id,profileId:app.profile_id,status}); syncJob(s,app.job_id); save(s); return one(s,'SELECT * FROM applications WHERE id=?',[aid]); }
function due(s){ return all(s,'SELECT * FROM tasks WHERE status="open" ORDER BY due_at IS NULL,due_at,created_at'); }
function research(s,jid,type){ const job=one(s,'SELECT * FROM jobs WHERE id=?',[jid]); if(!job) throw Error(`Unknown job: ${jid}`); const rel=type==='company'?path.join('jobs',jid,'company-dossier.md'):path.join('jobs',jid,'stakeholders.md'); const content= type==='company' ? `# Company research worksheet — ${job.company}\n\n**Related job:** ${job.title} (${job.id})\n**Source URL:** ${job.url || 'not provided'}\n\n## Known from imported job text\n- Company: ${job.company}\n- Location: ${job.location || 'not specified'}\n\n## Research to complete manually or with a future approved adapter\n- Website and product summary\n- Customers/market\n- Hiring-team evidence\n- Layoff/scam/ghost-job risk flags\n- Values/culture evidence with citations\n\n## Human gate\nThis MVP did not browse private accounts, scrape LinkedIn, or fabricate company facts.\n` : `# Stakeholder research worksheet — ${job.title}\n\n## Appropriate contacts to identify\n- Recruiter for this opening\n- Likely hiring manager\n- Team member or alumni connection\n\n## Suppression and relevance policy\n- Draft outreach only after relevance is documented.\n- Do not send messages from JobOS MVP.\n- Pause outreach if application stage changes to interview/offer/rejected unless user reviews.\n\n## Candidates\nNo people were inferred or fabricated. Add verified public profiles manually or via a future approved adapter.\n`; writeMd(path.join(s.p.ws,rel),content); audit(s,`research.${type}.created`,'job',jid,{jobId:jid,path:rel}); save(s); return {jobId:jid,path:rel,note:`${type} worksheet created; no external side effects.`}; }
function weekly(s,pid){ const prof=one(s,'SELECT * FROM profiles WHERE id=?',[pid]); if(!prof) throw Error(`Unknown profile: ${pid}`); const jobs=all(s,'SELECT * FROM jobs WHERE profile_id=? ORDER BY fit_score DESC,created_at DESC',[pid]), apps=all(s,'SELECT applications.*, jobs.title, jobs.company FROM applications JOIN jobs ON jobs.id=applications.job_id WHERE applications.profile_id=? ORDER BY applications.updated_at DESC',[pid]), tasks=due(s); const status=apps.reduce((a,x)=>(a[x.status]=(a[x.status]||0)+1,a),{}); const statusLines=Object.entries(status).map(([k,v])=>`- ${k}: ${v}`).join('\n')||'- No applications yet.'; const top=jobs.slice(0,5).map(x=>`- ${x.title} at ${x.company}: ${x.fit_score??'unscored'}/100 (${x.id})`).join('\n')||'- No jobs imported.'; const taskLines=tasks.slice(0,10).map(t=>`- ${t.title} (${t.priority}, ${t.due_at||'no due date'})`).join('\n')||'- No open tasks.'; const content=`# Weekly JobOS review — ${prof.name}\n\nGenerated: ${now()}\n\n## Funnel\n${statusLines}\n\n## Top jobs\n${top}\n\n## Due / open tasks\n${taskLines}\n\n## Suggested human actions\n- Score any unscored imported jobs.\n- Review evidence warnings before using tailored artifacts externally.\n- Update application statuses from real confirmations only.\n\n## Automation policy\nThis review is an internal summary. It did not submit applications or send outreach.\n`; const rel=path.join('exports',`weekly-review-${pid}-${new Date().toISOString().slice(0,10)}.md`); writeMd(path.join(s.p.ws,rel),content); const rid=id('run',`weekly-review:${pid}:${now()}`); run(s,'INSERT INTO automation_runs VALUES (?,?,?,?,?,?,?)',[rid,'weekly-review',JSON.stringify({profileId:pid}),JSON.stringify({path:rel,jobCount:jobs.length,openTaskCount:tasks.length}),'succeeded','none',now()]); audit(s,'automation.weekly_review','automation_run',rid,{profileId:pid,path:rel}); save(s); return {runId:rid,path:rel,content}; }
function state(s){ return {profiles:all(s,'SELECT id,name,preferences_json,created_at,updated_at FROM profiles ORDER BY created_at'),jobs:listJobs(s).map(x=>({...x,score:j(x.score_json,null),requirements:j(x.requirements_json,[])})),applications:all(s,'SELECT applications.*, jobs.title, jobs.company FROM applications JOIN jobs ON jobs.id=applications.job_id ORDER BY applications.updated_at DESC'),artifacts:all(s,'SELECT id,job_id,profile_id,type,path,title,warnings_json,approval_status,created_at FROM artifacts ORDER BY created_at DESC').map(a=>({...a,warnings:j(a.warnings_json,[])})),tasks:due(s),audit:all(s,'SELECT id,action,entity_type,entity_id,payload_json,external_side_effect,created_at FROM audit_log ORDER BY created_at DESC LIMIT 50').map(a=>({...a,payload:j(a.payload_json,{})})),automationRuns:all(s,'SELECT * FROM automation_runs ORDER BY created_at DESC LIMIT 25'),policy:{externalApply:'human_approval_required',externalSend:'human_approval_required',autoApply:'disabled',autoSend:'disabled'}}; }
function html(st){
  const profiles=st.profiles.map(p=>`<article class="card"><h3>${esc(p.name)}</h3><p><code>${esc(p.id)}</code></p><button class="copy" data-copy="jobos profile create '${esc(p.name)}'">Copy CLI</button></article>`).join('')||'<p class="muted">No profiles yet. Run <code>jobos profile create "PM EdTech"</code>.</p>';
  const profileOptions=st.profiles.map(p=>`<option>${esc(p.name)} (${esc(p.id)})</option>`).join('')||'<option>No profile yet</option>';
  const jobs=st.jobs;
  const highFit=jobs.filter(j=>(j.fit_score||0)>=60).slice(0,3);
  const todayCards=[...st.tasks.slice(0,3).map(t=>`<article class="card"><h3>${esc(t.title)}</h3><p class="muted">Task · ${esc(t.priority)} · ${esc(t.due_at||'no due date')}</p><a href="#tasks">Open tasks</a></article>`),...highFit.map(j=>`<article class="card"><h3>${esc(j.title)}</h3><p>${esc(j.company)} · <span class="pill" aria-label="Fit score ${j.fit_score}">${j.fit_score}/100</span></p><a href="#jobs">Review job</a></article>`)].slice(0,3).join('')||'<p class="muted">No priority actions yet. Create a profile, import a job, then score it.</p>';
  const jobRows=jobs.map(x=>`<tr><td><strong>${esc(x.title)}</strong><br><span class="muted">${esc(x.id)}</span></td><td>${esc(x.company)}</td><td><span class="pill" aria-label="Fit score ${x.fit_score??'unscored'}">${x.fit_score??'—'}</span></td><td><span class="pill" aria-label="Application status ${x.application_status||'not tracked'}">${esc(x.application_status||'not tracked')}</span></td><td>${esc(x.url||'manual')}</td><td><button class="copy" data-copy="jobos score ${esc(x.id)} --profile ${esc(x.profile_id)} --json">Copy score CLI</button></td></tr>`).join('')||'<tr><td colspan="6" class="muted">No jobs imported. Run <code>jobos jobs import-text --profile &lt;profile&gt; --file samples/job-description.md</code>.</td></tr>';
  const appCards=st.applications.map(a=>`<article class="card"><h3>${esc(a.title)}</h3><p>${esc(a.company)}</p><p><span class="pill" aria-label="Application status ${a.status}">${esc(a.status)}</span></p><button class="gate" data-kind="submit" data-context="${esc(a.title)} at ${esc(a.company)}">Review & Submit</button></article>`).join('')||'<p class="muted">No applications yet. Create one from a scored job.</p>';
  const artifactItems=st.artifacts.map(a=>`<li><strong>${esc(a.type)}</strong>: <a href="/workspace/${esc(a.path)}">${esc(a.title)}</a> <span class="pill" aria-label="Approval status ${a.approval_status}">${esc(a.approval_status)}</span>${a.warnings?.length?`<ul>${a.warnings.map(w=>`<li><span class="tag warn">Needs user input</span> ${esc(w)}</li>`).join('')}</ul>`:'<span class="tag ok">Directly supported</span>'}<br><button class="review-artifact" data-id="${esc(a.id)}">Review artifact</button> <button class="copy" data-copy="open jobos-workspace/${esc(a.path)}">Copy file command</button></li>`).join('')||'<li class="muted">No artifacts yet. Tailor a resume or cover letter to create draft artifacts.</li>';
  const taskItems=st.tasks.map(t=>`<li><strong>${esc(t.title)}</strong> <span class="pill" aria-label="Task priority ${t.priority}">${esc(t.priority)}</span> <span class="muted">${esc(t.due_at||'no due date')}</span></li>`).join('')||'<li class="muted">No open tasks.</li>';
  const researchRows=jobs.map(j=>`<tr><td>${esc(j.company)}</td><td>${esc(j.title)}</td><td><a href="/workspace/jobs/${esc(j.id)}/company-dossier.md">Company dossier</a></td><td><a href="/workspace/jobs/${esc(j.id)}/stakeholders.md">Stakeholders</a></td><td><button class="copy" data-copy="jobos research company --job ${esc(j.id)} --json">Copy research CLI</button></td></tr>`).join('')||'<tr><td colspan="5" class="muted">No jobs yet, so no research worksheets.</td></tr>';
  const auditRows=(st.audit||[]).map(a=>`<tr><td>${esc(a.created_at)}</td><td>${esc(a.action)}</td><td>${esc(a.entity_type)}</td><td><code>${esc(a.entity_id)}</code></td><td>${esc(a.external_side_effect)}</td></tr>`).join('')||'<tr><td colspan="5" class="muted">No audit entries yet.</td></tr>';
  const automationRows=(st.automationRuns||[]).map(r=>`<tr><td>${esc(r.trigger_name)}</td><td>${esc(r.status)}</td><td>${esc(r.external_side_effects)}</td><td>${esc(r.created_at)}</td></tr>`).join('')||'<tr><td colspan="4" class="muted">No automation runs yet. Run weekly review to create one.</td></tr>';
  const stateJson=JSON.stringify(st).replace(/</g,'\\u003c');
  return `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>JobOS Local Dashboard</title><style>
:root{color-scheme:light dark;font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}body{margin:0;background:#0f172a;color:#e2e8f0}.app{display:grid;grid-template-columns:220px 1fr;min-height:100vh}.rail{background:#020617;border-right:1px solid #334155;padding:18px;position:sticky;top:0;height:100vh}.rail a{display:flex;justify-content:space-between;color:#cbd5e1;text-decoration:none;padding:10px;border-radius:10px}.rail a:focus,.rail a:hover,.rail a.active{outline:2px solid #93c5fd;background:#1e293b}.count{font-size:12px;color:#93c5fd}.top{position:sticky;top:0;z-index:2;background:#111827;border-bottom:1px solid #334155;padding:16px;display:flex;gap:12px;align-items:center;flex-wrap:wrap}main{padding:24px;display:grid;gap:20px}.screen{display:none}.screen.active{display:grid;gap:20px}section,.panel{background:#111827;border:1px solid #334155;border-radius:16px;padding:18px;box-shadow:0 10px 30px rgba(0,0,0,.18)}h1,h2,h3{margin-top:0}.banner{background:#422006;border-color:#a16207;color:#fef3c7}.grid{display:grid;gap:12px;grid-template-columns:repeat(auto-fit,minmax(220px,1fr))}.card{background:#0b1220;border:1px solid #334155;border-radius:12px;padding:14px}.muted{color:#94a3b8}.pill,.tag{display:inline-block;border:1px solid #475569;border-radius:999px;padding:2px 8px;font-size:12px;color:#cbd5e1;background:#1e293b}.tag.warn{border-color:#a16207;color:#fef3c7;background:#422006}.tag.ok{border-color:#15803d;color:#dcfce7;background:#052e16}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:10px;border-bottom:1px solid #334155;vertical-align:top}code{background:#020617;border:1px solid #334155;border-radius:6px;padding:1px 5px}button,select,input{border:1px solid #475569;background:#0b1220;color:#e2e8f0;border-radius:10px;padding:8px 10px}button:focus,input:focus,select:focus{outline:3px solid #93c5fd;outline-offset:2px}.modal{position:fixed;inset:0;display:none;place-items:center;background:rgba(2,6,23,.78);z-index:10}.modal.open{display:grid}.dialog{max-width:760px;width:calc(100% - 32px);background:#111827;border:1px solid #94a3b8;border-radius:16px;padding:20px;box-shadow:0 20px 80px rgba(0,0,0,.5)}.two{display:grid;grid-template-columns:1.3fr .9fr;gap:16px}.error{display:none;background:#450a0a;border:1px solid #dc2626;color:#fee2e2;border-radius:12px;padding:12px}.palette{position:fixed;top:80px;left:50%;transform:translateX(-50%);width:min(560px,calc(100% - 32px));display:none;z-index:9}.palette.open{display:block}@media(max-width:760px){.app{grid-template-columns:1fr}.rail{position:fixed;bottom:0;top:auto;height:auto;width:100%;z-index:3;display:flex;gap:4px;overflow:auto;padding:8px}.rail h2{display:none}.rail a{font-size:12px;white-space:nowrap}.top{top:0;margin-bottom:54px}main{padding:14px 14px 76px}.two{grid-template-columns:1fr}table,thead,tbody,tr,td,th{display:block}thead{display:none}tr{border:1px solid #334155;border-radius:12px;margin-bottom:10px;padding:8px}td{border:0;padding:6px}}
</style></head><body><div class="app"><nav class="rail" aria-label="Primary"><h2>JobOS</h2><a href="#today">Today <span class="count">${st.tasks.length}</span></a><a href="#jobs">Jobs <span class="count">${st.jobs.length}</span></a><a href="#applications">Applications <span class="count">${st.applications.length}</span></a><a href="#artifacts">Artifacts <span class="count">${st.artifacts.length}</span></a><a href="#research">Research</a><a href="#outreach">Outreach</a><a href="#tasks">Tasks <span class="count">${st.tasks.length}</span></a><a href="#profile-proof">Profile & Proof</a><a href="#automations">Automations</a><a href="#audit">Audit Log</a></nav><div><header class="top"><strong>JobOS Local Dashboard</strong><label>Profile <select aria-label="Active profile">${profileOptions}</select></label><input id="search" aria-label="Search jobs and artifacts" placeholder="Search local state"><button id="refresh">Refresh</button><button id="paletteBtn">Cmd/Ctrl+K</button><span id="statusLive" aria-live="polite" class="muted">Reading local state from SQLite mirror.</span></header><main><div id="errorBox" class="error" role="alert"></div><section class="banner" aria-label="External action policy" aria-live="assertive"><strong>Human gate:</strong> this MVP can draft, score, track, and summarize. It cannot submit applications, send outreach, or touch external accounts.</section>
<section id="today" class="screen"><h1>Today / Priority Brief</h1><div class="grid">${todayCards}</div><div class="panel"><h2>Pending approvals</h2><p>${st.artifacts.length ? `${st.artifacts.length} draft artifact(s) need review.` : 'No artifacts pending review.'}</p></div></section>
<section id="jobs" class="screen"><h1>Jobs</h1><table><thead><tr><th scope="col">Role</th><th scope="col">Company</th><th scope="col">Score</th><th scope="col">Application</th><th scope="col">Source</th><th scope="col">Agent action</th></tr></thead><tbody>${jobRows}</tbody></table></section>
<section id="applications" class="screen"><h1>Applications</h1><div class="grid">${appCards}</div><p class="muted">Changing real external application state requires manual confirmation through the CLI or the job site.</p></section>
<section id="artifacts" class="screen"><h1>Artifacts</h1><div class="two"><div class="panel"><h2>Review queue</h2><ul>${artifactItems}</ul></div><div class="panel"><h2>Evidence legend</h2><p><span class="tag ok">Directly supported</span> Stored proof point supports the claim.</p><p><span class="tag warn">Needs user input</span> Missing or unmatched evidence.</p><p><span class="tag">Reasonably reframed</span> Human should confirm wording.</p><p><span class="tag warn">Not allowed</span> Do not use externally.</p></div></div></section>
<section id="research" class="screen"><h1>Research</h1><table><thead><tr><th scope="col">Company</th><th scope="col">Job</th><th scope="col">Dossier</th><th scope="col">Stakeholders</th><th scope="col">Agent action</th></tr></thead><tbody>${researchRows}</tbody></table></section>
<section id="outreach" class="screen"><h1>Outreach</h1><div class="panel"><p class="muted">No outreach threads are sent or synced in this MVP. Use stakeholder worksheets to draft manually.</p><button class="gate" data-kind="send" data-context="outreach draft">Review & Send</button></div></section>
<section id="tasks" class="screen"><h1>Tasks</h1><ul>${taskItems}</ul></section>
<section id="profile-proof" class="screen"><h1>Profile & Proof</h1><div class="grid">${profiles}</div><p class="muted">Proof libraries are mirrored under <code>jobos-workspace/proof-points/</code>.</p></section>
<section id="automations" class="screen"><h1>Automations</h1><div class="panel"><h2>Schedules</h2><p><code>weekly-review</code> is implemented as a manual internal automation. <code>daily-discovery</code> is design-only and does not auto-apply.</p><button class="copy" data-copy="jobos review weekly --profile ${esc(st.profiles[0]?.id||'<profile>')} --output markdown">Copy weekly review CLI</button></div><table><thead><tr><th scope="col">Run</th><th scope="col">Status</th><th scope="col">External side effects</th><th scope="col">Created</th></tr></thead><tbody>${automationRows}</tbody></table></section>
<section id="audit" class="screen"><h1>Audit Log</h1><table><thead><tr><th scope="col">Time</th><th scope="col">Action</th><th scope="col">Entity</th><th scope="col">ID</th><th scope="col">External side effect</th></tr></thead><tbody>${auditRows}</tbody></table></section>
</main></div></div><div id="palette" class="palette panel"><label>Command palette <input id="paletteInput" aria-label="Command palette search" placeholder="Type a job, application, or artifact ID"></label><p class="muted">Shortcuts: g then j = Jobs, g then a = Applications, g then t = Tasks.</p></div><div id="modal" class="modal" role="dialog" aria-modal="true" aria-labelledby="modalTitle"><div class="dialog"><h2 id="modalTitle">Human review required</h2><div id="modalBody"></div><label><input id="reviewCheck" type="checkbox"> I reviewed this and understand JobOS will not perform the external action.</label><p><button id="modalClose">Close</button></p></div></div><script>window.__JOBOS_STATE__=${stateJson};
const links=[...document.querySelectorAll('.rail a')], screens=[...document.querySelectorAll('.screen')], live=document.getElementById('statusLive'), modal=document.getElementById('modal'), body=document.getElementById('modalBody'), title=document.getElementById('modalTitle');
function route(){const id=(location.hash||'#today').slice(1); screens.forEach(s=>s.classList.toggle('active',s.id===id)); links.forEach(a=>a.classList.toggle('active',a.getAttribute('href')==='#'+id));}
addEventListener('hashchange',route); route();
document.getElementById('refresh').onclick=async()=>{try{live.textContent='Refreshing local state...'; const r=await fetch('/api/state'); if(!r.ok) throw new Error('HTTP '+r.status); await r.json(); live.textContent='Local state reachable. Reload page to render latest snapshot.';}catch(e){document.getElementById('errorBox').style.display='block';document.getElementById('errorBox').textContent='Dashboard cannot read local API: '+e.message;live.textContent='Local API error.';}};
document.querySelectorAll('.copy').forEach(b=>b.onclick=async()=>{await navigator.clipboard?.writeText(b.dataset.copy||''); live.textContent='Copied CLI command.';});
document.querySelectorAll('.gate').forEach(b=>b.onclick=()=>{title.textContent='External action gate'; body.innerHTML='<p><strong>'+b.textContent+'</strong> for '+(b.dataset.context||'this item')+'</p><p>JobOS MVP has no connector for sending, submitting, or applying. Complete the action manually in the external system after review.</p>'; modal.classList.add('open'); document.getElementById('reviewCheck').focus();});
document.querySelectorAll('.review-artifact').forEach(b=>b.onclick=()=>{const a=window.__JOBOS_STATE__.artifacts.find(x=>x.id===b.dataset.id); title.textContent='Artifact review'; body.innerHTML='<div class="two"><div><h3>'+a.title+'</h3><p><a href="/workspace/'+a.path+'">Open Markdown artifact</a></p><p><strong>Approval:</strong> '+a.approval_status+'</p><h4>Diff</h4><p class="muted">No prior version is available in this MVP; compare against the proof library before external use.</p></div><div><h3>Evidence & config</h3>'+(a.warnings.length?a.warnings.map(w=>'<p><span class="tag warn">Needs user input</span> '+w+'</p>').join(''):'<p><span class="tag ok">Directly supported</span> No deterministic evidence warnings.</p>')+'<p><strong>Generator:</strong> deterministic local template; model: none.</p><button class="gate" data-kind="submit" data-context="artifact '+a.id+'">Review & Submit</button><button disabled title="Approval command is future scope">Approve</button><button disabled title="Change-request command is future scope">Request changes</button></div></div>'; modal.classList.add('open');});
document.getElementById('modalClose').onclick=()=>modal.classList.remove('open'); modal.addEventListener('click',e=>{if(e.target===modal)modal.classList.remove('open')});
const palette=document.getElementById('palette'); function togglePalette(){palette.classList.toggle('open'); if(palette.classList.contains('open')) document.getElementById('paletteInput').focus();}
document.getElementById('paletteBtn').onclick=togglePalette; addEventListener('keydown',e=>{if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){e.preventDefault();togglePalette();} if(e.key==='g') window.__g=true; else if(window.__g){if(e.key==='j') location.hash='jobs'; if(e.key==='a') location.hash='applications'; if(e.key==='t') location.hash='tasks'; window.__g=false;}});
</script></body></html>`; }
function web(s,{port=4317,host='127.0.0.1'}={}){ const server=http.createServer((req,res)=>{ const raw=req.url||'/'; if(raw.startsWith('/workspace/') && /(\.\.|%2e%2e)/i.test(raw)){res.writeHead(400);res.end('Bad workspace path');return;} const u=new URL(raw,`http://${req.headers.host}`); if(u.pathname==='/api/state'){ res.writeHead(200,{'content-type':'application/json; charset=utf-8'}); res.end(JSON.stringify(state(s),null,2)); return;} if(u.pathname.startsWith('/workspace/')){ const rel=u.pathname.replace(/^\/workspace\//,''), abs=path.resolve(s.p.ws,rel); if(!abs.startsWith(s.p.ws)||!fs.existsSync(abs)||fs.statSync(abs).isDirectory()){res.writeHead(404);res.end('Not found');return;} res.writeHead(200,{'content-type':'text/plain; charset=utf-8'}); res.end(fs.readFileSync(abs)); return;} if(u.pathname!=='/'){res.writeHead(404);res.end('Not found');return;} res.writeHead(200,{'content-type':'text/html; charset=utf-8'}); res.end(html(state(s))); }); server.listen(port,host); return server; }
function parse(argv){ const out={_:[],flags:{}}; for(let i=0;i<argv.length;i++){ const a=argv[i]; if(a.startsWith('--')){ const k=a.slice(2); if(k.includes('=')){ const [kk,...vv]=k.split('='); out.flags[kk]=vv.join('='); } else if(i+1<argv.length && !argv[i+1].startsWith('--')) out.flags[k]=argv[++i]; else out.flags[k]=true; } else out._.push(a); } return out; }
function out(v,flags={}){ if(flags.json) console.log(JSON.stringify(v,null,2)); else if(typeof v==='string') console.log(v); else console.log(JSON.stringify(v,null,2)); }
function needProfile(flags){ if(!flags.profile) throw Error('Missing --profile <profile-id>'); return String(flags.profile); }
async function main(){ const parsed=parse(process.argv.slice(2)), flags=parsed.flags, [group,action,subaction,...rest]=parsed._, s=await open(flags); if(!group||group==='help'||flags.help){ out(`JobOS local-first MVP\n\nCommands:\n  jobos init [--json]\n  jobos profile create <name> [--from-resume file] [--json]\n  jobos proof add --profile <profile> --summary <text> [--evidence <text>] [--skills a,b]\n  jobos jobs import-text --profile <profile> --file <path> [--json]\n  jobos jobs import-url <url> --profile <profile> [--json]\n  jobos jobs list --json\n  jobos score <job-id> --profile <profile> --json\n  jobos tailor resume --job <job-id> --profile <profile> --output markdown\n  jobos tailor cover-letter --job <job-id> --profile <profile> --output markdown\n  jobos applications create --job <job-id> --status <status> [--json]\n  jobos applications update <application-id> --status <status> [--json]\n  jobos research company --job <job-id> [--json]\n  jobos research stakeholders --job <job-id> [--json]\n  jobos tasks due --json\n  jobos review weekly --profile <profile> --output markdown\n  jobos web [--port 4317]\n\nGlobal: --workspace <dir> or JOBOS_HOME.`, flags); return; }
 if(group==='init'){ out({ok:true,root:s.root,database:s.p.db,workspace:s.p.ws,policy:{externalActions:'human_approval_required'}},flags); return; }
 if(group==='profile'&&action==='create'){ const name=rest.length?[subaction,...rest].filter(Boolean).join(' '):subaction; if(!name) throw Error('Missing profile name'); const r=createProfile(s,name,{fromResume:flags['from-resume'],preferences:flags.preferences}); out({id:r.profile.id,name:r.profile.name,created:r.created,preferences:j(r.profile.preferences_json,{})},flags); return; }
 if(group==='proof'&&action==='add'){ if(!flags.summary) throw Error('Missing --summary'); const p=addProof(s,needProfile(flags),String(flags.summary),flags.evidence?String(flags.evidence):'',flags.skills?String(flags.skills).split(',').map(x=>x.trim()).filter(Boolean):[]); out({id:p.id,profileId:p.profile_id,summary:p.summary},flags); return; }
 if(group==='jobs'&&action==='import-text'){ if(!flags.file) throw Error('Missing --file <path>'); const r=importText(s,{profileId:needProfile(flags),filePath:flags.file}); out({id:r.job.id,title:r.job.title,company:r.job.company,created:r.created},flags); return; }
 if(group==='jobs'&&action==='import-url'){ const url=subaction||flags.url; if(!url) throw Error('Missing URL'); const r=await importUrl(s,{profileId:needProfile(flags),url}); out({id:r.job.id,title:r.job.title,company:r.job.company,url:r.job.url,created:r.created},flags); return; }
 if(group==='jobs'&&action==='list'){ out(listJobs(s).map(x=>({id:x.id,title:x.title,company:x.company,profileId:x.profile_id,score:x.fit_score,applicationStatus:x.application_status||null,url:x.url})),flags); return; }
 if(group==='score'){ if(!action) throw Error('Missing job id'); out(score(s,action,needProfile(flags)),flags); return; }
 if(group==='tailor'&&action==='resume'){ if(!flags.job) throw Error('Missing --job'); const r=tailor(s,flags.job,needProfile(flags),'resume'); if(flags.output==='markdown') console.log(fs.readFileSync(path.join(s.p.ws,r.path),'utf8')); else out(r,flags); return; }
 if(group==='tailor'&&action==='cover-letter'){ if(!flags.job) throw Error('Missing --job'); const r=tailor(s,flags.job,needProfile(flags),'cover'); if(flags.output==='markdown') console.log(fs.readFileSync(path.join(s.p.ws,r.path),'utf8')); else out(r,flags); return; }
 if(group==='applications'&&action==='create'){ if(!flags.job||!flags.status) throw Error('Missing --job or --status'); const a=appCreate(s,flags.job,String(flags.status),flags.notes?String(flags.notes):''); out({id:a.id,jobId:a.job_id,profileId:a.profile_id,status:a.status},flags); return; }
 if(group==='applications'&&action==='update'){ if(!subaction||!flags.status) throw Error('Missing application id or --status'); const a=appUpdate(s,subaction,String(flags.status),flags.notes?String(flags.notes):null); out({id:a.id,jobId:a.job_id,profileId:a.profile_id,status:a.status},flags); return; }
 if(group==='research'&&action==='company'){ if(!flags.job) throw Error('Missing --job'); out(research(s,flags.job,'company'),flags); return; }
 if(group==='research'&&action==='stakeholders'){ if(!flags.job) throw Error('Missing --job'); out(research(s,flags.job,'stakeholders'),flags); return; }
 if(group==='tasks'&&action==='due'){ out(due(s).map(t=>({id:t.id,title:t.title,dueAt:t.due_at,priority:t.priority,status:t.status,jobId:t.job_id})),flags); return; }
 if(group==='review'&&action==='weekly'){ const r=weekly(s,needProfile(flags)); if(flags.output==='markdown') console.log(r.content); else out({runId:r.runId,path:r.path},flags); return; }
 if(group==='web'){ const port=flags.port?Number(flags.port):4317, host=flags.host?String(flags.host):'127.0.0.1'; const server=web(s,{port,host}); console.log(`JobOS dashboard running at http://${host}:${port}`); process.on('SIGTERM',()=>server.close(()=>process.exit(0))); process.on('SIGINT',()=>server.close(()=>process.exit(0))); return; }
 throw Error(`Unknown command: ${process.argv.slice(2).join(' ')}`); }
main().catch(e=>{ const wantsJson = process.argv.includes('--json'); if (wantsJson) console.error(JSON.stringify({ok:false,error:e.message}, null, 2)); else console.error(`jobos: ${e.message}`); process.exitCode=1; });
